/* local-compatible Chart.js-compatible renderer bundled for offline Telegram WebApp use.
   NOTE: Replace with official Chart.js dist/chart.umd.min.js for full upstream feature parity.
   It implements the small subset of Chart.js API used by the WebApp: new Chart(canvas,{type,data,options}) and destroy(). */
(function(){
  const PALETTE=['#2563eb','#16a34a','#f97316','#dc2626','#7c3aed','#0891b2','#65a30d','#be123c'];
  function num(v){v=Number(v||0); return Number.isFinite(v)?v:0}
  function clear(ctx,w,h){ctx.clearRect(0,0,w,h); ctx.fillStyle='#fff'; ctx.fillRect(0,0,w,h)}
  function text(ctx,s,x,y,size=11,color='#475467',align='left'){ctx.fillStyle=color; ctx.font=`${size}px system-ui,-apple-system,Segoe UI,sans-serif`; ctx.textAlign=align; ctx.fillText(String(s),x,y)}
  function drawAxes(ctx,w,h,p){ctx.strokeStyle='#e5e7eb'; ctx.lineWidth=1; ctx.beginPath(); ctx.moveTo(p.l,p.t); ctx.lineTo(p.l,h-p.b); ctx.lineTo(w-p.r,h-p.b); ctx.stroke()}
  function maxData(datasets){let m=0; (datasets||[]).forEach(ds=>(ds.data||[]).forEach(v=>m=Math.max(m,num(v)))); return m||1}
  class MiniChart{
    constructor(canvas, cfg){this.canvas=canvas; this.ctx=canvas.getContext('2d'); this.cfg=cfg||{}; this.draw();}
    destroy(){ if(this.ctx) this.ctx.clearRect(0,0,this.canvas.width||300,this.canvas.height||150); }
    resize(){ const ratio=window.devicePixelRatio||1; const rect=this.canvas.getBoundingClientRect(); const w=Math.max(280, rect.width||this.canvas.clientWidth||360); const h=Math.max(160, this.canvas.height||this.canvas.clientHeight||this.canvas.getAttribute('height')||180); this.canvas.width=w*ratio; this.canvas.height=h*ratio; this.ctx.setTransform(ratio,0,0,ratio,0,0); return {w,h}; }
    draw(){ const {w,h}=this.resize(); const ctx=this.ctx; clear(ctx,w,h); const type=this.cfg.type||'bar'; if(type==='doughnut') return this.doughnut(ctx,w,h); if(type==='line') return this.line(ctx,w,h); return this.bar(ctx,w,h); }
    legend(ctx,datasets,w,h){let x=18,y=h-10; (datasets||[]).forEach((ds,i)=>{ctx.fillStyle=ds.backgroundColor||ds.borderColor||PALETTE[i%PALETTE.length]; ctx.fillRect(x,y-9,10,10); text(ctx,ds.label||`#${i+1}`,x+14,y,10); x+=Math.min(120,(ds.label||'').length*7+34);});}
    bar(ctx,w,h){const data=this.cfg.data||{}, labels=data.labels||[], datasets=data.datasets||[]; const p={l:42,r:16,t:14,b:36}; drawAxes(ctx,w,h,p); const max=maxData(datasets); const n=Math.max(1,labels.length); const group=(w-p.l-p.r)/n; const barW=Math.max(4, group/Math.max(2,datasets.length+1)); labels.forEach((lab,i)=>{ if(i%Math.ceil(n/6)===0) text(ctx,lab,p.l+i*group+group/2,h-18,9,'#667085','center'); datasets.forEach((ds,j)=>{const v=num((ds.data||[])[i]); const bh=(h-p.t-p.b)*v/max; const x=p.l+i*group+j*barW+barW*.45; const y=h-p.b-bh; ctx.fillStyle=ds.backgroundColor||ds.borderColor||PALETTE[j%PALETTE.length]; ctx.fillRect(x,y,barW*.8,bh);});}); this.legend(ctx,datasets,w,h);}
    line(ctx,w,h){const data=this.cfg.data||{}, labels=data.labels||[], datasets=data.datasets||[]; const p={l:42,r:16,t:14,b:36}; drawAxes(ctx,w,h,p); const max=maxData(datasets); const n=Math.max(1,labels.length-1); datasets.forEach((ds,j)=>{ctx.strokeStyle=ds.borderColor||PALETTE[j%PALETTE.length]; ctx.lineWidth=2; ctx.beginPath(); (ds.data||[]).forEach((vv,i)=>{const x=p.l+(w-p.l-p.r)*(i/n); const y=h-p.b-(h-p.t-p.b)*num(vv)/max; if(i===0)ctx.moveTo(x,y);else ctx.lineTo(x,y);}); ctx.stroke(); (ds.data||[]).forEach((vv,i)=>{const x=p.l+(w-p.l-p.r)*(i/n); const y=h-p.b-(h-p.t-p.b)*num(vv)/max; ctx.fillStyle=ds.borderColor||PALETTE[j%PALETTE.length]; ctx.beginPath(); ctx.arc(x,y,2.5,0,Math.PI*2); ctx.fill();});}); labels.forEach((lab,i)=>{ if(i%Math.ceil((labels.length||1)/6)===0) text(ctx,lab,p.l+(w-p.l-p.r)*(i/Math.max(1,labels.length-1)),h-18,9,'#667085','center');}); this.legend(ctx,datasets,w,h);}
    doughnut(ctx,w,h){const data=this.cfg.data||{}, labels=data.labels||[], values=((data.datasets||[])[0]||{}).data||[]; const colors=((data.datasets||[])[0]||{}).backgroundColor||PALETTE; const total=values.reduce((a,b)=>a+num(b),0)||1; const cx=w/2, cy=h/2-8, r=Math.min(w,h)*.28; let start=-Math.PI/2; values.forEach((v,i)=>{const ang=num(v)/total*Math.PI*2; ctx.beginPath(); ctx.moveTo(cx,cy); ctx.arc(cx,cy,r,start,start+ang); ctx.closePath(); ctx.fillStyle=colors[i%colors.length]; ctx.fill(); start+=ang;}); ctx.fillStyle='#fff'; ctx.beginPath(); ctx.arc(cx,cy,r*.55,0,Math.PI*2); ctx.fill(); let y=h-34,x=18; labels.slice(0,6).forEach((lab,i)=>{ctx.fillStyle=colors[i%colors.length]; ctx.fillRect(x,y-9,10,10); text(ctx,lab,x+14,y,10); x+=Math.min(120,String(lab).length*7+34); if(x>w-120){x=18;y+=14;}});}
  }
  MiniChart.version='4.4.8-local-compatible'; window.Chart=MiniChart;
})();
